Given an input string counts the number of occurences of each word in
the string.  All non characters (not in [a-z] or [A-Z]) are replaced
with a blank, and all upper-case characters are converted to lower
case.  A word is a maximal contiguous sequence of characters in the
resulting string.

The output is a sequence of pairs, each consisting of a string (word)
and a count of how many times it appears. Ordering does not matter.

### Default Input Distributions

Instances consist of both synthetic and real strings.

The large instances are:

- A trigram string of length 250 Million, generated with:  
`trigramString 250000000 <filename>`

- `etext99` is text from the project Guttenberg.  It has about 105
Million characters.

- `wikipedia250M.txt` is a sample from wikipedia's xml source files.  It has 
exactly 250 million characters.

The small instances are:

- A trigram string of length 25 Million, generated with:  
`trigramString 25000000 <filename>`

- `wikisamp.xml` is a sample from wikipedia's xml source files.  It has 
exactly 100 million characters.

### Input and Output File Formats

The input is a text file and output need to be in the [sequence file format](../fileFormats/sequence.html),
with type `StringIntPair`.The function signature is:

```cpp
#include "parlay/primitives.h"

using charseq = parlay::sequence<char>;
using result_type = std::pair<charseq,size_t>;
parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose);


```
Baseline Code Impl:

```cpp
// --- Start of file: wc.C ---
#include <iostream>
#include <unordered_map>
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "wc.h"

using namespace std;

parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
  parlay::internal::timer t("word counts", verbose);
  if (verbose)
    cout << "number of characters = " << s.size() << endl;

  // copy to mutable vector and convert non alpha chars to spaces
  vector<char> str(s.size()+1);
  for (size_t i=0; i < s.size(); i++) {
    char c = s[i];
    if (c >= 65 && c < 91) str[i] = c + 32;   // upper to lower
    else if (c >= 97 && c < 123) str[i] = c;  // already lower
    else str[i] = ' ';                     // all other
  }
  str[s.size()] = 0;
  t.next("copy");

  // tokenize
  vector<char*> tokens;
  char* next_token = strtok(str.data(), " ");
  size_t count = 0;
  while (next_token != NULL) {
    tokens.push_back(next_token);
    next_token = strtok (NULL, "\r\n\t ");
    count++;
  }
  if (verbose)
    cout << "number of words = " << count << endl;
  t.next("tokenize");

  // define a hash table
  auto strhash = [] (char* s) -> size_t {
    size_t hash = 5381;
    char* l = s;
    while (*l != 0) {
      hash = ((hash << 5) + hash) + *l; l++;}
    return hash;
  };

  auto streql = [] (char* a, char* b) {
    return strcmp(a,b) == 0;};

  unordered_map<char*, size_t, decltype(strhash), decltype(streql)> word_map(count, strhash, streql);

  // add each token to the word_map
  for (size_t i=0; i < count; i++)
    ++word_map[tokens[i]];
  t.next("insert into hash table");
  if (verbose)
    cout << "result size = " << word_map.size() << endl;

  // pull out elements into a sequence
  parlay::sequence<result_type> result;
  result.reserve(word_map.size());
  for (const auto &pair : word_map) 
    result.push_back(result_type(parlay::to_chars(pair.first),pair.second));
  t.next("extract results");

  return result;
}

// --- End of file: wc.C ---


```

