	      make_tuple(s[j], s[j+1], rank[j+2]));
  };

  //parlay::sequence<uint> SA(n-1);
  int offset = (n%3 == 1);
  parlay::sequence<uint> SA = parlay::merge(SA0.cut(offset, n0),
					  SA12.cut(1 - offset, n12),
