  // Does not use ranks.
  void link(vertexId u, vertexId v) {
    parents[u] = v;}

  // returns true if successful
  bool tryLink(vertexId u, vertexId v) {
    return (parents[u] == -1 &&
	    pbbs::atomic_compare_and_swap(&parents[u], -1, v));
  }
};

