		cout << "query " << i << ", naive: " << t << ", PAM: " << res << endl;
		total_check += t;
	}
  cout << "total: " << total << endl;
  cout << "total_check: " << total_check << endl;
#endif

  r.clear();
  t.next("clear");
  return total;
}

